// Compose one lead_enrichment row from the three service responses.
// Fail-soft: a failed traffic or social call does NOT fail enrichment. Only a
// missing funnel_type makes enrichment 'failed' (audit worker can't run without it).
const lead = $('Loop leads').item.json;
const funnel = $('Detect Funnel').item.json || {};
const traffic = $('Get Traffic').item.json || {};
const social = $('Get Social Posts').item.json || {};

const funnelType = funnel.funnel_type || null;
const hasFunnel = !!funnelType;

return [{ json: {
  lead_id: lead.id,
  traffic_estimate: (traffic.traffic_estimate ?? null),
  tech_stack: funnel.tech_stack || {},
  funnel_entry_url: funnel.funnel_entry_url || null,
  funnel_type: funnelType,
  form_selector: funnel.form_selector || null,
  recent_social_posts: Array.isArray(social.posts) ? social.posts : [],
  enrichment_status: hasFunnel ? 'complete' : 'failed',
  enrichment_failure_reason: hasFunnel ? null : (funnel.reason || 'no discoverable funnel'),
  // carried for the event log
  _social_reason: social.reason || null,
  _traffic_reason: traffic.reason || null
}}];
